<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import type { SecretProfileSummary } from '../../shared/contracts'
import PageHeader from '../components/PageHeader.vue'
import PathField from '../components/PathField.vue'
const provider=ref('agnes');const mediaType=ref('image');const output=ref('');const promptFile=ref('');const interval=ref(90);const concurrency=ref(1);const maxErrors=ref(3);const running=ref(false);const profiles=ref<SecretProfileSummary[]>([]);const credentialProfileId=ref('')
const availableProfiles=computed(()=>profiles.value.filter(profile=>profile.provider.toLowerCase()===provider.value&&profile.unlocked))
onMounted(async()=>{profiles.value=await window.mel.secrets.list();credentialProfileId.value=availableProfiles.value[0]?.id??''})
async function run(){running.value=true;try{await window.mel.jobs.create({kind:'automation',title:`${provider.value} ${mediaType.value} automation`,config:{provider:provider.value,media_type:mediaType.value,output_path:output.value,prompt_file:promptFile.value,interval_seconds:interval.value,concurrency:concurrency.value,max_consecutive_errors:maxErrors.value,credential_profile_id:credentialProfileId.value}})}finally{running.value=false}}
</script>
<template><div class="page-wrap"><PageHeader eyebrow="Media Automation" title="Rate-conscious generation orchestration" subtitle="Credentials remain outside project files. Configure pacing, concurrency, retry boundaries and durable output verification." icon="mdi-robot-outline" color="accent"/><v-alert v-if="!availableProfiles.length" type="warning" variant="tonal" class="mb-5" title="No unlocked Agnes credential">Create or unlock a compatible credential profile in Settings. The API key will be injected only into the isolated engine process.</v-alert><v-card class="glass pa-6"><v-row><v-col cols="12" md="4"><v-select v-model="provider" label="Provider" :items="['agnes']" prepend-inner-icon="mdi-cloud-outline"/></v-col><v-col cols="12" md="4"><v-select v-model="credentialProfileId" label="Credential profile" :items="availableProfiles.map(profile=>({title:`${profile.name} · ${profile.backend}`,value:profile.id}))" prepend-inner-icon="mdi-key-chain-variant"/></v-col><v-col cols="12" md="4"><v-select v-model="mediaType" label="Media type" :items="['image','video']" prepend-inner-icon="mdi-movie-open-outline"/></v-col><v-col cols="12" md="4"><v-text-field v-model.number="interval" type="number" label="Call interval (seconds)" prepend-inner-icon="mdi-timer-outline"/></v-col><v-col cols="12" md="4"><v-text-field v-model.number="concurrency" type="number" min="1" max="8" label="Concurrency" prepend-inner-icon="mdi-call-split"/></v-col><v-col cols="12" md="4"><v-text-field v-model.number="maxErrors" type="number" label="Stop after consecutive errors" prepend-inner-icon="mdi-alert-octagon-outline"/></v-col><v-col cols="12"><PathField v-model="promptFile" label="Prompt file or directory"/><PathField v-model="output" label="Generated media output"/></v-col></v-row><v-btn color="primary" prepend-icon="mdi-play" :loading="running" :disabled="!output||!promptFile||!credentialProfileId" @click="run">Start durable automation</v-btn></v-card></div></template>
